import React, { useEffect, useState } from "react";
import "./ExpenseUI.css";

function AddTravel({ employee }) {
  const [form, setForm] = useState({
    travel_date: "",
    from: "",
    to: "",
    purpose: "",
    mode_of_travel: "",
    amount: "",
  });

  const [travelList, setTravelList] = useState([]);

  // 🔹 Fetch travel history
  const fetchTravel = async () => {
    try {
      const res = await fetch(
        `https://prasa-backend-1.onrender.com/travel/${employee.empld}`
      );
      const data = await res.json();
      setTravelList(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("Fetch error:", err);
    }
  };

  useEffect(() => {
    fetchTravel();
  }, []);

  const saveTravel = async () => {
    try {
      await fetch("https://prasa-backend-1.onrender.com/travel/add", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, empld: employee.empld }),
      });

      alert("Travel expense added!");
      fetchTravel();
      setForm({
        travel_date: "",
        from: "",
        to: "",
        purpose: "",
        mode_of_travel: "",
        amount: "",
      });
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div className="expense-container">
      <h2 className="page-title">Travel Expense</h2>

      <div className="expense-card">
        <div className="grid-3">
          <input
            type="date"
            value={form.travel_date}
            onChange={(e) => setForm({ ...form, travel_date: e.target.value })}
            className="input-box"
            placeholder="Travel Date"
          />

          <input
            type="text"
            value={form.from}
            onChange={(e) => setForm({ ...form, from: e.target.value })}
            className="input-box"
            placeholder="From"
          />

          <input
            type="text"
            value={form.to}
            onChange={(e) => setForm({ ...form, to: e.target.value })}
            className="input-box"
            placeholder="To"
          />

          <input
            type="text"
            value={form.purpose}
            onChange={(e) => setForm({ ...form, purpose: e.target.value })}
            className="input-box"
            placeholder="Purpose"
          />

          <input
            type="text"
            value={form.mode_of_travel}
            onChange={(e) =>
              setForm({ ...form, mode_of_travel: e.target.value })
            }
            className="input-box"
            placeholder="Mode of Travel"
          />

          <input
            type="number"
            value={form.amount}
            onChange={(e) => setForm({ ...form, amount: e.target.value })}
            className="input-box"
            placeholder="Amount"
          />
        </div>

        <button className="save-btn" onClick={saveTravel}>
          Save Travel Expense
        </button>
      </div>

      <h3 className="section-title">Travel History</h3>

      {travelList.length === 0 ? (
        <p className="empty">No records found</p>
      ) : (
        <div className="table-wrapper">
          <table className="custom-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>From</th>
                <th>To</th>
                <th>Purpose</th>
                <th>Mode</th>
                <th>Amount</th>
              </tr>
            </thead>
            <tbody>
              {travelList.map((t, i) => (
                <tr key={i}>
                  <td>{t.travel_date}</td>
                  <td>{t.location_from}</td>
                  <td>{t.location_to}</td>
                  <td>{t.purpose}</td>
                  <td>{t.mode_of_travel}</td>
                  <td>₹{t.amount}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default AddTravel;
